/usr/bin/bash -lc "python - <<'PY'
import json,re
from pathlib import Path
terms=['30 police','30 security','police and security personnel','Lorestan','Sistan and Baluchestan','Chaharmahal','Kurdistan','Isfahan','Basij','Iranian state television','state TV','IRIB']
for p in sorted(Path('articles/2026/01').glob('*/articles.jsonl')):
    rows=[]
    for i,line in enumerate(p.open()):
        a=json.loads(line); text=((a.get('title') or '')+'\\n'+(a.get('content') or ''))
        low=text.lower()
        if ('iran' in low or 'iranian' in low or 'tehran' in low or 'protests' in low) and any(t.lower() in low for t in terms):
            rows.append((i,[t for t in terms if t.lower() in low],a.get('date_publish'),a.get('source'),a.get('title') or '',text[:1400].replace('\\n',' | ')))
    if rows:
        print('\\nFILE',p,'matches',len(rows))
        for row in rows[:60]:
            print('IDX',row[0],'HITS',row[1],'DATE',row[2],'SRC',row[3]); print(row[4]); print(row[5])
PY"

